lib/email/resend.ts (서버 전용, NEXT_PUBLIC_ 금지, 클라이언트 import 금지):
  export async function sendEmail({to,subject,html}): Promise<{ok:boolean}> {
    const key=process.env.RESEND_API_KEY, from=process.env.EMAIL_FROM;
    if(!key||!from){ console.warn('[email] RESEND 미설정 — skip'); return {ok:false}; }
    try{ const res=await fetch('https://api.resend.com/emails',{method:'POST',headers:{Authorization:`Bearer ${key}`,'Content-Type':'application/json'},body:JSON.stringify({from,to,subject,html})}); if(!res.ok){console.error('[email]', await res.text()); return {ok:false};} return {ok:true}; }catch(e){ console.error('[email]', e); return {ok:false}; }
  }
